Here are the public test cases for feature6_presence_checks:
{
  "description": "Reports whether keys are present before storage, after storage, and after deletion.",
  "cases": [
    {
      "input": {
        "scenario": "check key presence",
        "probe_before": [
          "foo",
          "spam"
        ],
        "entries": [
          {
            "key": "foo",
            "value": "bar"
          }
        ],
        "probe_after_store": [
          "foo",
          "spam"
        ],
        "delete_keys": [
          "foo"
